+/**
+ * Webhook notification handler — dispatches HTTP callbacks when order
+ * events occur.
+ *
+ * Subscribes to order events through the EventBus, following the
+ * unified event-driven notification architecture.
+ *
+ * External consumers register webhook URLs for specific event types.
+ * When a matching event fires, the handler POSTs a JSON payload to
+ * each registered URL.
+ *
+ * Depends on:
+ * - EventBus (event system) for receiving order lifecycle events
+ */
+
+import type { EventBus } from '../events/event-bus.js';
+import type { EventType, AppEvent, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
+import { Logger } from '../utils/logger.js';
+
+export interface WebhookRegistration {
+  id: string;
+  url: string;
+  eventType: EventType;
+  secret?: string;
+  createdAt: Date;
+}
+
+export interface WebhookDelivery {
+  id: string;
+  webhookId: string;
+  url: string;
+  eventType: EventType;
+  payload: WebhookPayload;
+  success: boolean;
+  statusCode?: number;
+  error?: string;
+  deliveredAt: Date;
+}
+
+export interface WebhookPayload {
+  event: EventType;
+  timestamp: string;
+  data: Record<string, unknown>;
+}
+
+export type HttpPostFn = (url: string, payload: WebhookPayload, secret?: string) => Promise<{ statusCode: number }>;
+
+let nextWebhookId = 1;
+let nextDeliveryId = 1;
+
+function generateWebhookId(): string {
+  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
+}
+
+function generateDeliveryId(): string {
+  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
+}
+
+export function resetWebhookIdCounters(): void {
+  nextWebhookId = 1;
+  nextDeliveryId = 1;
+}
+
+export class WebhookHandler {
+  private logger = new Logger('WebhookHandler');
+  private registrations: WebhookRegistration[] = [];
+  private deliveries: WebhookDelivery[] = [];
+  private httpPost: HttpPostFn;
+
+  constructor(eventBus: EventBus, httpPost?: HttpPostFn) {
+    this.httpPost = httpPost ?? WebhookHandler.defaultHttpPost;
+    this.registerHandlers(eventBus);
+  }
+
+  private registerHandlers(eventBus: EventBus): void {
+    eventBus.on<OrderCreatedEvent>('order:created', (event) => {
+      return this.dispatchWebhooks('order:created', event);
+    });
+
+    eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
+      return this.dispatchWebhooks('order:status-changed', event);
+    });
+  }
+
+  /**
+   * Register an external URL to receive callbacks for a specific event type.
+   */
+  register(url: string, eventType: EventType, secret?: string): WebhookRegistration {
+    const registration: WebhookRegistration = {
+      id: generateWebhookId(),
+      url,
+      eventType,
+      secret,
+      createdAt: new Date(),
+    };
+    this.registrations.push(registration);
+    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
+    return registration;
+  }
+
+  /**
+   * Unregister a webhook by ID.
+   */
+  unregister(webhookId: string): boolean {
+    const index = this.registrations.findIndex((r) => r.id === webhookId);
+    if (index >= 0) {
+      this.registrations.splice(index, 1);
+      this.logger.info(`Webhook unregistered: ${webhookId}`);
+      return true;
+    }
+    return false;
+  }
+
+  /**
+   * Get all registered webhooks.
+   */
+  getRegistrations(): WebhookRegistration[] {
+    return [...this.registrations];
+  }
+
+  /**
+   * Get registrations for a specific event type.
+   */
+  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
+    return this.registrations.filter((r) => r.eventType === eventType);
+  }
+
+  /**
+   * Get all delivery records.
+   */
+  getDeliveries(): WebhookDelivery[] {
+    return [...this.deliveries];
+  }
+
+  /**
+   * Get deliveries for a specific webhook.
+   */
+  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
+    return this.deliveries.filter((d) => d.webhookId === webhookId);
+  }
+
+  /**
+   * Clear all registrations and delivery history.
+   */
+  clear(): void {
+    this.registrations = [];
+    this.deliveries = [];
+  }
+
+  private async dispatchWebhooks(eventType: EventType, event: AppEvent): Promise<void> {
+    const matching = this.registrations.filter((r) => r.eventType === eventType);
+    if (matching.length === 0) return;
+
+    const payload = this.buildPayload(eventType, event);
+
+    for (const registration of matching) {
+      await this.deliver(registration, payload);
+    }
+  }
+
+  private buildPayload(eventType: EventType, event: AppEvent): WebhookPayload {
+    const base = {
+      event: eventType,
+      timestamp: event.timestamp.toISOString(),
+    };
+
+    if (event.type === 'order:created') {
+      const e = event as OrderCreatedEvent;
+      return {
+        ...base,
+        data: {
+          orderId: e.order.id,
+          userId: e.order.userId,
+          items: e.order.items,
+          total: e.order.total,
+          status: e.order.status,
+        },
+      };
+    }
+
+    if (event.type === 'order:status-changed') {
+      const e = event as OrderStatusChangedEvent;
+      return {
+        ...base,
+        data: {
+          orderId: e.order.id,
+          userId: e.order.userId,
+          previousStatus: e.previousStatus,
+          newStatus: e.newStatus,
+        },
+      };
+    }
+
+    return { ...base, data: {} };
+  }
+
+  private async deliver(registration: WebhookRegistration, payload: WebhookPayload): Promise<void> {
+    const deliveryId = generateDeliveryId();
+
+    try {
+      const result = await this.httpPost(registration.url, payload, registration.secret);
+      this.deliveries.push({
+        id: deliveryId,
+        webhookId: registration.id,
+        url: registration.url,
+        eventType: registration.eventType,
+        payload,
+        success: result.statusCode >= 200 && result.statusCode < 300,
+        statusCode: result.statusCode,
+        deliveredAt: new Date(),
+      });
+      this.logger.info(`Webhook delivered: ${deliveryId} to ${registration.url} (${result.statusCode})`);
+    } catch (err) {
+      const message = err instanceof Error ? err.message : String(err);
+      this.deliveries.push({
+        id: deliveryId,
+        webhookId: registration.id,
+        url: registration.url,
+        eventType: registration.eventType,
+        payload,
+        success: false,
+        error: message,
+        deliveredAt: new Date(),
+      });
+      this.logger.info(`Webhook delivery failed: ${deliveryId} to ${registration.url} — ${message}`);
+    }
+  }
+
+  private static async defaultHttpPost(
+    _url: string,
+    _payload: WebhookPayload,
+    _secret?: string,
+  ): Promise<{ statusCode: number }> {
+    return { statusCode: 200 };
+  }
+}

