/**
 * Webhook notification handler — dispatches HTTP callbacks when order
 * events occur.
 *
 * Subscribes to order events through the EventBus, following the
 * unified event-driven notification architecture.
 *
 * External consumers register webhook URLs for specific event types.
 * When a matching event fires, the handler POSTs a JSON payload to
 * each registered URL.
 *
 * Depends on:
 * - EventBus (event system) for receiving order lifecycle events
 */

import type { EventBus } from '../events/event-bus.js';
import type { EventType, AppEvent, OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import { Logger } from '../utils/logger.js';

export interface WebhookRegistration {
  id: string;
  url: string;
  eventType: EventType;
  secret?: string;
  createdAt: Date;
}

export interface WebhookDelivery {
  id: string;
  webhookId: string;
  url: string;
  eventType: EventType;
  payload: WebhookPayload;
  success: boolean;
  statusCode?: number;
  error?: string;
  deliveredAt: Date;
}

export interface WebhookPayload {
  event: EventType;
  timestamp: string;
  data: Record<string, unknown>;
}

export type HttpPostFn = (url: string, payload: WebhookPayload, secret?: string) => Promise<{ statusCode: number }>;

let nextWebhookId = 1;
let nextDeliveryId = 1;

function generateWebhookId(): string {
  return `webhook-${String(nextWebhookId++).padStart(4, '0')}`;
}

function generateDeliveryId(): string {
  return `delivery-${String(nextDeliveryId++).padStart(4, '0')}`;
}

export function resetWebhookIdCounters(): void {
  nextWebhookId = 1;
  nextDeliveryId = 1;
}

export class WebhookHandler {
  private logger = new Logger('WebhookHandler');
  private registrations: WebhookRegistration[] = [];
  private deliveries: WebhookDelivery[] = [];
  private httpPost: HttpPostFn;

  constructor(eventBus: EventBus, httpPost?: HttpPostFn) {
    this.httpPost = httpPost ?? WebhookHandler.defaultHttpPost;
    this.registerHandlers(eventBus);
  }

  private registerHandlers(eventBus: EventBus): void {
    eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.dispatchWebhooks('order:created', event);
    });

    eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.dispatchWebhooks('order:status-changed', event);
    });
  }

  /**
   * Register an external URL to receive callbacks for a specific event type.
   */
  register(url: string, eventType: EventType, secret?: string): WebhookRegistration {
    const registration: WebhookRegistration = {
      id: generateWebhookId(),
      url,
      eventType,
      secret,
      createdAt: new Date(),
    };
    this.registrations.push(registration);
    this.logger.info(`Webhook registered: ${registration.id} for ${eventType} -> ${url}`);
    return registration;
  }

  /**
   * Unregister a webhook by ID.
   */
  unregister(webhookId: string): boolean {
    const index = this.registrations.findIndex((r) => r.id === webhookId);
    if (index >= 0) {
      this.registrations.splice(index, 1);
      this.logger.info(`Webhook unregistered: ${webhookId}`);
      return true;
    }
    return false;
  }

  /**
   * Get all registered webhooks.
   */
  getRegistrations(): WebhookRegistration[] {
    return [...this.registrations];
  }

  /**
   * Get registrations for a specific event type.
   */
  getRegistrationsForEvent(eventType: EventType): WebhookRegistration[] {
    return this.registrations.filter((r) => r.eventType === eventType);
  }

  /**
   * Get all delivery records.
   */
  getDeliveries(): WebhookDelivery[] {
    return [...this.deliveries];
  }

  /**
   * Get deliveries for a specific webhook.
   */
  getDeliveriesForWebhook(webhookId: string): WebhookDelivery[] {
    return this.deliveries.filter((d) => d.webhookId === webhookId);
  }

  /**
   * Clear all registrations and delivery history.
   */
  clear(): void {
    this.registrations = [];
    this.deliveries = [];
  }

  private async dispatchWebhooks(eventType: EventType, event: AppEvent): Promise<void> {
    const matching = this.registrations.filter((r) => r.eventType === eventType);
    if (matching.length === 0) return;

    const payload = this.buildPayload(eventType, event);

    for (const registration of matching) {
      await this.deliver(registration, payload);
    }
  }

  private buildPayload(eventType: EventType, event: AppEvent): WebhookPayload {
    const base = {
      event: eventType,
      timestamp: event.timestamp.toISOString(),
    };

    if (event.type === 'order:created') {
      const e = event as OrderCreatedEvent;
      return {
        ...base,
        data: {
          orderId: e.order.id,
          userId: e.order.userId,
          items: e.order.items,
          total: e.order.total,
          status: e.order.status,
        },
      };
    }

    if (event.type === 'order:status-changed') {
      const e = event as OrderStatusChangedEvent;
      return {
        ...base,
        data: {
          orderId: e.order.id,
          userId: e.order.userId,
          previousStatus: e.previousStatus,
          newStatus: e.newStatus,
        },
      };
    }

    return { ...base, data: {} };
  }

  private async deliver(registration: WebhookRegistration, payload: WebhookPayload): Promise<void> {
    const deliveryId = generateDeliveryId();

    try {
      const result = await this.httpPost(registration.url, payload, registration.secret);
      this.deliveries.push({
        id: deliveryId,
        webhookId: registration.id,
        url: registration.url,
        eventType: registration.eventType,
        payload,
        success: result.statusCode >= 200 && result.statusCode < 300,
        statusCode: result.statusCode,
        deliveredAt: new Date(),
      });
      this.logger.info(`Webhook delivered: ${deliveryId} to ${registration.url} (${result.statusCode})`);
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      this.deliveries.push({
        id: deliveryId,
        webhookId: registration.id,
        url: registration.url,
        eventType: registration.eventType,
        payload,
        success: false,
        error: message,
        deliveredAt: new Date(),
      });
      this.logger.info(`Webhook delivery failed: ${deliveryId} to ${registration.url} — ${message}`);
    }
  }

  private static async defaultHttpPost(
    _url: string,
    _payload: WebhookPayload,
    _secret?: string,
  ): Promise<{ statusCode: number }> {
    return { statusCode: 200 };
  }
}

import { describe, it, expect, beforeEach, vi } from 'vitest';
import { EventBus } from '../../src/events/event-bus.js';
import {
  WebhookHandler,
  resetWebhookIdCounters,
  type HttpPostFn,
  type WebhookPayload,
} from '../../src/notifications/webhook.handler.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';

function makeOrderCreatedEvent(overrides: Partial<OrderCreatedEvent> = {}): OrderCreatedEvent {
  return {
    type: 'order:created',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
      total: 20,
      status: 'pending',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    user: {
      id: 'user-1',
      name: 'Alice',
      email: 'alice@example.com',
      role: 'member',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    timestamp: new Date('2026-01-01T12:00:00Z'),
    ...overrides,
  };
}

function makeStatusChangedEvent(
  overrides: Partial<OrderStatusChangedEvent> = {},
): OrderStatusChangedEvent {
  return {
    type: 'order:status-changed',
    order: {
      id: 'order-1',
      userId: 'user-1',
      items: [],
      total: 20,
      status: 'shipped',
      createdAt: new Date('2026-01-01'),
      updatedAt: new Date('2026-01-01'),
    },
    previousStatus: 'confirmed',
    newStatus: 'shipped',
    timestamp: new Date('2026-01-01T12:00:00Z'),
    ...overrides,
  };
}

describe('WebhookHandler', () => {
  let eventBus: EventBus;
  let mockPost: ReturnType<typeof vi.fn<HttpPostFn>>;
  let handler: WebhookHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    mockPost = vi.fn<HttpPostFn>().mockResolvedValue({ statusCode: 200 });
    handler = new WebhookHandler(eventBus, mockPost);
    resetWebhookIdCounters();
  });

  describe('webhook registration', () => {
    it('should register a webhook and return a registration', () => {
      const reg = handler.register('https://example.com/hook', 'order:created');

      expect(reg.id).toBe('webhook-0001');
      expect(reg.url).toBe('https://example.com/hook');
      expect(reg.eventType).toBe('order:created');
      expect(reg.createdAt).toBeInstanceOf(Date);
    });

    it('should generate sequential webhook IDs', () => {
      const r1 = handler.register('https://a.com', 'order:created');
      const r2 = handler.register('https://b.com', 'order:status-changed');

      expect(r1.id).toBe('webhook-0001');
      expect(r2.id).toBe('webhook-0002');
    });

    it('should store optional secret', () => {
      const reg = handler.register('https://example.com/hook', 'order:created', 'my-secret');
      expect(reg.secret).toBe('my-secret');
    });

    it('should list all registrations', () => {
      handler.register('https://a.com', 'order:created');
      handler.register('https://b.com', 'order:status-changed');

      expect(handler.getRegistrations()).toHaveLength(2);
    });

    it('should filter registrations by event type', () => {
      handler.register('https://a.com', 'order:created');
      handler.register('https://b.com', 'order:status-changed');
      handler.register('https://c.com', 'order:created');

      expect(handler.getRegistrationsForEvent('order:created')).toHaveLength(2);
      expect(handler.getRegistrationsForEvent('order:status-changed')).toHaveLength(1);
    });

    it('should unregister a webhook by ID', () => {
      const reg = handler.register('https://a.com', 'order:created');
      expect(handler.unregister(reg.id)).toBe(true);
      expect(handler.getRegistrations()).toHaveLength(0);
    });

    it('should return false when unregistering non-existent webhook', () => {
      expect(handler.unregister('webhook-9999')).toBe(false);
    });
  });

  describe('order:created webhook delivery', () => {
    it('should POST to registered URL when order is created', async () => {
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).toHaveBeenCalledTimes(1);
      const [url, payload] = mockPost.mock.calls[0]!;
      expect(url).toBe('https://example.com/hook');
      expect(payload.event).toBe('order:created');
      expect(payload.data).toEqual({
        orderId: 'order-1',
        userId: 'user-1',
        items: [{ productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 }],
        total: 20,
        status: 'pending',
      });
    });

    it('should include timestamp in ISO format', async () => {
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      const payload = mockPost.mock.calls[0]![1] as WebhookPayload;
      expect(payload.timestamp).toBe('2026-01-01T12:00:00.000Z');
    });

    it('should pass secret to httpPost', async () => {
      handler.register('https://example.com/hook', 'order:created', 'secret-123');
      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).toHaveBeenCalledWith(
        'https://example.com/hook',
        expect.any(Object),
        'secret-123',
      );
    });

    it('should deliver to multiple registered webhooks', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).toHaveBeenCalledTimes(2);
    });

    it('should not fire for unmatched event types', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');
      await eventBus.emit(makeOrderCreatedEvent());

      expect(mockPost).not.toHaveBeenCalled();
    });
  });

  describe('order:status-changed webhook delivery', () => {
    it('should POST status change data', async () => {
      handler.register('https://example.com/hook', 'order:status-changed');
      await eventBus.emit(makeStatusChangedEvent());

      expect(mockPost).toHaveBeenCalledTimes(1);
      const payload = mockPost.mock.calls[0]![1] as WebhookPayload;
      expect(payload.event).toBe('order:status-changed');
      expect(payload.data).toEqual({
        orderId: 'order-1',
        userId: 'user-1',
        previousStatus: 'confirmed',
        newStatus: 'shipped',
      });
    });
  });

  describe('delivery tracking', () => {
    it('should record successful deliveries', async () => {
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(true);
      expect(deliveries[0]?.statusCode).toBe(200);
      expect(deliveries[0]?.url).toBe('https://example.com/hook');
    });

    it('should record failed deliveries on non-2xx status', async () => {
      mockPost.mockResolvedValue({ statusCode: 500 });
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.statusCode).toBe(500);
    });

    it('should record delivery errors when HTTP call throws', async () => {
      mockPost.mockRejectedValue(new Error('Connection refused'));
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries).toHaveLength(1);
      expect(deliveries[0]?.success).toBe(false);
      expect(deliveries[0]?.error).toBe('Connection refused');
      expect(deliveries[0]?.statusCode).toBeUndefined();
    });

    it('should filter deliveries by webhook ID', async () => {
      const reg1 = handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      expect(handler.getDeliveriesForWebhook(reg1.id)).toHaveLength(1);
      expect(handler.getDeliveriesForWebhook(reg1.id)[0]?.url).toBe('https://a.com/hook');
    });

    it('should generate sequential delivery IDs', async () => {
      handler.register('https://a.com/hook', 'order:created');
      handler.register('https://b.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      const deliveries = handler.getDeliveries();
      expect(deliveries[0]?.id).toBe('delivery-0001');
      expect(deliveries[1]?.id).toBe('delivery-0002');
    });
  });

  describe('clear', () => {
    it('should clear registrations and delivery history', async () => {
      handler.register('https://example.com/hook', 'order:created');
      await eventBus.emit(makeOrderCreatedEvent());

      handler.clear();
      expect(handler.getRegistrations()).toHaveLength(0);
      expect(handler.getDeliveries()).toHaveLength(0);
    });
  });

  describe('coexistence with other handlers', () => {
    it('should work alongside NotificationService and EmailNotificationHandler', async () => {
      const { NotificationService, resetNotificationIdCounter } = await import(
        '../../src/services/notification.service.js'
      );
      const { EmailNotificationHandler, resetEmailIdCounter } = await import(
        '../../src/notifications/email-notification.handler.js'
      );

      const sharedBus = new EventBus();
      resetNotificationIdCounter();
      resetEmailIdCounter();
      resetWebhookIdCounters();

      const notifService = new NotificationService(sharedBus);
      const emailHandler = new EmailNotificationHandler(sharedBus);
      const localPost = vi.fn<HttpPostFn>().mockResolvedValue({ statusCode: 200 });
      const webhookHandler = new WebhookHandler(sharedBus, localPost);
      webhookHandler.register('https://partner.com/orders', 'order:created');

      await sharedBus.emit(makeOrderCreatedEvent());

      expect(notifService.getNotificationCount()).toBe(1);
      expect(emailHandler.getSentEmailCount()).toBe(1);
      expect(localPost).toHaveBeenCalledTimes(1);
      expect(webhookHandler.getDeliveries()).toHaveLength(1);
    });
  });
});
